  'changzhou/pagoda': ('معبد تياننينغ', 'يرتفع هذا المعبد في وسط المدينة ليصل طوله إلى 153 متراً، مما يجعله أطول معبد في العالم.'),
  'changzhou/comb': ('حرفة الأمشاط', 'كانت أمشاط تشانغتشو المصنوعة يدوياً منذ آلاف السنين تُقدم كهدايا للقصور الإمبراطورية.'),
  'changzhou/canal': ('القناة الكبرى', 'يستمتع الزوار بالتنزه على ضفاف القناة لاستكشاف الأحياء القديمة ومشاهدة أضواء الليل.'),
  'shaoxing/wine': ('نبيذ شاوشينغ', 'يُصنع هنا منذ آلاف السنين نبيذ الأرز الأصفر الشهير الذي يُعد عنصراً أساسياً في المطبخ الصيني.'),
  'shaoxing/bridge': ('الجسور الحجرية', 'تحتفظ مدينة شاوشينغ، التي تتخللها القنوات المائية، بمئات الجسور الحجرية المقوسة.'),
  'shaoxing/pen': ('مهد الخط العربي', 'يُعتبر جناح الأوركيد الخاص بالخطاط الشهير وانغ شي تشي موقعاً مقدساً لفن الخط الصيني.'),
  'shaoxing/boat': ('قوارب ووبنغ', 'تُعد قوارب "ووبنغ" ذات المظلات السوداء، التي تُدفع بالأقدام، وسيلة التنقل الكلاسيكية في القنوات المائية.'),
  'bengbu/shell': ('ميناء اللؤلؤ', 'يعني اسم المدينة "رصيف المحار"، وقد اشتهرت قديماً بإنتاج لآلئ نهر هواي.'),
  'bengbu/train': ('بوابة السكك الحديدية', 'تعد مدينة بنغبو نقطة عبور رئيسية لخطوط السكك الحديدية بين شمال الصين وجنوبها، وقد ازدهرت المدينة بفضل محطتها المركزية.'),
  'bengbu/river': ('نهر هواي', 'يجري هذا النهر عبر المدينة، ويُعتبر تاريخياً الخط الفاصل الطبيعي بين شمال الصين وجنوبها.'),
  'bengbu/blossom': ('مهرجانات الربيع', 'تكتسي المتنزهات المطلة على ضفاف النهر بحلة زاهية خلال مهرجانات تفتح الأزهار في فصل الربيع.'),
  'jiujiang/mountain': ('جبل لو', 'تُعد قمم جبل لو الضبابية، المدرجة ضمن قائمة اليونسكو للتراث العالمي، مصدراً لإلهام الشعراء والرسامين عبر العصور.'),
  'jiujiang/tea': ('شاي السحاب والضباب', 'يُعتبر شاي "يون وو" المستخلص من منحدرات جبل لو من بين أرقى أنواع الشاي الصيني وأكثرها دقة في المذاق.'),
  'jiujiang/lake': ('بحيرة بويانغ', 'تُعد بحيرة بويانغ أكبر بحيرة للمياه العذبة في الصين، وتستقبل آلاف الطيور المهاجرة خلال فصل الشتاء.'),
  'jiujiang/scroll': ('مدينة القصائد', 'خُطت أبيات كبار الشعراء مثل باي جويي وسو شي على بوابات هذه المدينة المطلة على النهر.'),
  'quanzhou/ship': ('طريق الحرير البحري', 'كانت مدينة تشوانتشو، التي عرفها ماركو بولو باسم "زيتون"، أعظم ميناء في العالم خلال العصور الوسطى وهي مدرجة ضمن قائمة اليونسكو.'),
  'quanzhou/mosque': ('مسجد تشينغجينغ', 'يُعد هذا المسجد الحجري الذي شُيد عام 1009 ميلادي من بين أقدم المساجد التاريخية في الصين.'),
  'quanzhou/puppet': ('فن العرائس', 'يُعتبر فن تحريك العرائس بالخيوط في تشوانتشو تقليداً مسرحياً عريقاً يعود تاريخه إلى ألف عام.'),
  'quanzhou/tea': ('شاي تيغوانين', 'يُعرف شاي الأولونغ القادم من منطقة أنشي المجاورة عالمياً باسم شاي "الإلهة الحديدية".'),
  'shanghai/pearl': ('برج لؤلؤة الشرق', 'يُعد هذا البرج، بكراته الوردية الشاهقة فوق نهر هوانغبو، الرمز الأبرز لمدينة شنغهاي الحديثة.'),
  'shanghai/bund': ('منطقة البوند', 'تعكس واجهات الفنادق والمباني التاريخية على ضفاف النهر عظمة شنغهاي القديمة.'),
  'shanghai/garden': ('حديقة يو', 'تُشكل هذه الحديقة الكلاسيكية التي تعود إلى عصر أسرة مينغ، بصخورها وبركها المائية، واحة هادئة في قلب المدينة.'),
  'shanghai/xlb': ('زلابية الحساء', 'تُعد هذه الفطائر المطهوة على البخار والمحشوة بالمرق الساخن تحفة فنية في وجبات الإفطار بشنغهاي.'),
  'hangzhou/lake': ('البحيرة الغربية', 'تعد هذه البحيرة، بما تضمه من أشجار الصفصاف والجزر والجسور المقوسة، أكثر البحيرات التي تغنى بها الشعراء في الأدب الصيني.'),
  'hangzhou/tea': ('شاي لونغجينغ', 'يُزرع شاي "بئر التنين" الأخضر على المنحدرات المحيطة بالبحيرة، ويُعتبر أشهر أنواع الشاي في الصين.'),
  'hangzhou/temple': ('معبد لينغين', 'يشتهر هذا المعبد الذي يعود تاريخه إلى 1700 عام، والمعروف باسم "معبد ملاذ الروح"، بنقوشه الصخرية وتمثال بوذا العملاق.'),
  'hangzhou/silk': ('مدينة الحرير', 'يُنسج حرير هانغتشو منذ ألف عام، وهو الذي شكل ثروة الطرف الشرقي لطريق الحرير التاريخي.'),
  'chongqing/hongya': ('كهف هونغيا', 'مجمع من المنازل المبنية على ركائز متينة فوق المنحدر الصخري، يتلألأ ليلاً فوق النهر كأنه مشهد من القصص الخيالية.'),
  'chongqing/hotpot': ('قدر تشونغتشينغ الساخن', 'يُعد القدر الساخن، بمرقه المغلي المليء بالزيوت الحارة والفلفل المخدر، الروح النارية لهذه المدينة الجبلية.'),
  'chongqing/monorail': ('قطار تشونغتشينغ المعلق', 'يُعد القطار الخفيف الذي يخترق المباني السكنية المشهد الأيقوني لهذه المدينة المبنية فوق التلال.'),
  'chongqing/river': ('مضايق نهر يانغتسي', 'تنطلق رحلات السفن السياحية عبر المضايق الثلاثة من هذا الميناء، حيث ترتفع المدينة عند نقطة التقاء نهرين.'),
  'dalian/square': ('ساحة شينغهاي', 'تعد هذه الساحة الأكبر من نوعها في آسيا، وتنبض بالحياة خلال المهرجانات والعروض المقامة على طول الواجهة البحرية.'),
  'dalian/beach': ('شواطئ داليان', 'بفضل خلجانها الصخرية وصيفها المعتدل، تُعتبر داليان الوجهة الساحلية المفضلة في شمال الصين.'),
  'dalian/football': ('مدينة كرة القدم', 'تُلقب داليان بـ "مهد كرة القدم" في الصين، حيث نشأت فيها أكثر الأندية تتويجاً بالألقاب في البلاد.'),
  'dalian/seafood': ('مأكولات داليان البحرية', 'تتزين موائد المدينة بأشهى المأكولات البحرية من مياه البحر الأصفر الباردة، مثل الإسكالوب والروبيان وقنفذ البحر.'),
  'shenyang/palace': ('قصر موكدين', 'هو القصر الأول لسلالة تشينغ، ويُعتبر بمثابة الشقيق الأصغر للمدينة المحرمة في بكين.'),
  'shenyang/tomb': ('مقابر تشينغ', 'تُعد المقابر الشرقية والشمالية التي تحيط بالمدينة أضرحة أثرية ضخمة لمؤسسي سلالة تشينغ.'),
  'shenyang/factory': ('مهد الصناعة', 'وُلدت الصناعات الثقيلة الصينية هنا، وقد أكسبتها مصانعها الضخمة لقب "رور الشرق".'),
  'shenyang/dumpling': ('زلابية لاوبيان', 'تُعد زلابية لاوبيان المطهوة على البخار، والتي يعود تاريخها إلى مئتي عام، الطبق المميز على المائدة الشمالية.'),
  'hefei/judge': ('ضريح القاضي باو', 'وُلد القاضي العادل باو تشنغ هنا، ويُعتبر ضريحه رمزاً للنزاهة والعدالة.'),
  'hefei/science': ('مدينة العلوم', 'مركز تقني يضم نخبة من الجامعات والمختبرات الرائدة في الصين.'),
  'hefei/lake': ('بحيرة تشاوهو', 'تُعد واحدة من أكبر خمس بحيرات للمياه العذبة في الصين، وتشتهر بأسماكها البيضاء وسرطان البحر.'),
  'hefei/cake': ('كعكة السمسم لو', 'تعتبر كعكة السمسم المحشوة بالحلوى من أقدم الحلويات التقليدية في مدينة لوتشو القديمة.'),
  'foshan/wingchun': ('وينغ تشون', 'تُعد المدينة موطن فن الوينغ تشون القتالي، حيث تعود إليها جذور المعلم ييب مان وبروس لي.'),
  'foshan/lion': ('رقصة الأسد', 'تُعتبر المدينة عاصمة رقصة الأسد الجنوبية، حيث تقفز الأسود الملونة ببراعة فوق الأعمدة خلال المهرجانات.'),
  'foshan/ceramic': ('فخار شيوان', 'لا تزال أفران الفخار التي يعود تاريخها إلى ألف عام تنتج تماثيل شيوان الحيوية.'),
  'foshan/opera': ('أوبرا كانتونية', 'تطورت فنون المسرح الأكثر شعبية في جنوب الصين على هذه الأراضي.'),
  'guiyang/pavilion': ('جناح جياشيو', 'يُعد هذا الجناح المكون من ثلاث طبقات والمطل على نهر نانمينغ رمزاً للمدينة منذ أربعمئة عام.'),
  'guiyang/sourfish': ('حساء السمك الحامض', 'يُعد السمك المطهو في مرق الطماطم المخمرة الحامضة الطبق المميز لمقاطعة قويتشو.'),
  'guiyang/waterfall': ('شلالات هوانغغوشو', 'تتدفق واحدة من أكبر شلالات آسيا بقوة، مما يخلق أقواس قزح مذهلة في الأفق.'),
  'guiyang/miao': ('ثقافة مياو', 'تضفي مهرجانات وتطريزات شعب المياو، الذين يرتدون التيجان الفضية، بهجةً على القرى الجبلية.'),
  'changchun/film': ('مدينة السينما', 'تضم المدينة الاستوديوهات التي وُلدت فيها السينما الصينية، وتُعرف بلقب هوليوود الشرق.'),
  'changchun/car': ('مدينة السيارات', 'خرجت أول سيارة صينية الصنع من مصانع هذه المدينة، التي تُعد العاصمة الوطنية لصناعة السيارات.'),
  'changchun/palace': ('قصر الإمبراطور الأخير', 'يعد هذا القصر الذي عاش فيه آخر أباطرة الصين شاهداً صامتاً على حقبة تاريخية مضطربة.'),
  'changchun/snow': ('ثلوج الشتاء', 'تتألق المدينة خلال فصول الشتاء الطويلة بمنحوتات جليدية ومسارات للتزلج وسط بياض الثلوج.'),
  'xining/lake': ('بحيرة تشينغهاي', 'تُعرف أكبر بحيرة مالحة في الصين بحقول زهور اللفت الصفراء التي تحيط بها في فصل الصيف.'),
  'xining/monastery': ('دير كومبوم', 'يُعد أحد الأديرة الستة الكبرى للبوذية التبتية، ويشتهر بمنحوتاته المصنوعة من زبدة الياك.'),
  'xining/flower': ('زهور اللفت', 'تكتسي الهضبة في شهر يوليو بحقول ذهبية من زهور اللفت تمتد حتى الأفق.'),
  'xining/lamb': ('لحم الياك والضأن', 'تتميز نكهات الهضبة بأطباق المعكرونة المسحوبة يدوياً وأسياخ لحم الضأن التي تشتهر بها مطابخ قوميتي هوي والتبت.'),
  'guilin/karst': ('تضاريس كارست على نهر لي', 'تعد القمم الكلسية التي ترتفع وسط الضباب المشهد المطبوع على ورقة العشرين يوان النقدية.'),
  'guilin/elephant': ('تلة جذع الفيل', 'تعتبر الصخرة التي تتخذ شكل فيل يغمس خرطومه في النهر الرمز المحبوب للمدينة.'),
  'guilin/terrace': ('مصاطب لونغجي للأرز', 'تُشكل مصاطب \'عمود فقري للتنين\' التي تلتف حول المنحدرات سلماً يعكس قروناً من الكد والعمل.'),
  'guilin/osmanthus': ('زهور الأوسمانثوس', 'يعني اسم المدينة \'غابة الأوسمانثوس\'، حيث تغرق المدينة في الخريف بعبير أزهارها العطرية.'),
  'wenzhou/merchant': ('روح التجارة', 'يُعرف رواد الأعمال في ونتشو ببراعتهم التجارية، حيث أسسوا شبكات أعمال تمتد عبر أرجاء العالم.'),
  'wenzhou/shoe': ('الأحذية والجلود', 'تنتج هذه المدينة الصناعية حصة ضخمة من الأحذية الجلدية التي تُباع في جميع أنحاء العالم.'),
  'wenzhou/mountain': ('جبال ياندانغ', 'تُعرف هذه الجبال بشلالاتها وقممها المسننة، وتُلقب بـ \'الجبل الأول المطل على البحر\'.'),
  'wenzhou/seafood': ('المأكولات البحرية', 'تعتمد المائدة المحلية في ونتشو بشكل أساسي على الحبار والمحار والأسماك المستخرجة من بحر الصين الشرقي.'),
  'tangshan/memorial': ('نصب تذكاري لزلزال تانغشان', 'يعد الحديقة التذكارية لزلزال عام 1976 الكبير رمزاً لمدينة ولدت من جديد.'),
  'tangshan/coal': ('منجم الفحم والصلب', 'تُعد هذه المدينة مهد الصناعة الصينية، حيث افتُتح فيها أول منجم فحم وسكة حديدية حديثة في البلاد.'),
  'tangshan/ceramic': ('خزف تانغشان', 'تُلقب بمدينة الخزف في الشمال، حيث يزين صيني العظام الفاخر الذي تنتجه موائد الطعام بأناقة فائقة.'),
  'tangshan/lake': ('حديقة نانهو', 'تحولت حفرة منجم قديمة إلى حديقة بحيرة خلابة أصبحت بمثابة الرئة الخضراء للمدينة.'),
  'anshan/steel': ('مدينة الصلب', 'تأسس فيها أكبر مصنع للصلب في الصين، مما جعلها تُعرف بلقب عاصمة الصلب الوطنية.'),
  'anshan/jade': ('يشم شيويان', 'تضم المدينة أكبر منحوتة يشم في العالم، وتُعتبر بحق أرض اليشم في الصين.'),
  'anshan/mountain': ('جبل تشيان', 'يُعرف بجبل قمم اللوتس الألف، وهو قمة مقدسة في الشمال تشتهر بمعابدها ومنحدراتها الصخرية.'),
  'anshan/spring': ('ينابيع تانغغانغزي', 'ينابيع حارة يقصدها الناس للاستشفاء منذ ألف عام، وقد كانت وجهة مفضلة للأباطرة قديماً.'),
  'linyi/market': ('سوق الجملة', 'يُعد أكبر مركز لتجارة الجملة في شمال الصين، حيث تُشحن البضائع منه إلى جميع أنحاء البلاد.'),
  'linyi/brush': ('موطن الخطاطين', 'وُلد فيها حكيم الخط الصيني وانغ شي تشي، وتُعرف المدينة بأنها أرض الحبر والفنون.'),
  'linyi/mountain': ('جبل منغ', 'يُعد ثاني أعلى جبل في مقاطعة شاندونغ، وهو بمثابة منتجع طبيعي غني بالهواء النقي والشلالات.'),
  'linyi/pancake': ('فطائر ييمينغ', 'تُعتبر فطائر الذرة الرقيقة المعروفة باسم جيان بينغ الغذاء الأساسي التقليدي لسكان جبال ييمينغ.'),
  'cangzhou/lion': ('الأسد الحديدي', 'يُعد تمثال الأسد الحديدي الضخم الذي يعود تاريخه إلى ألف ومئة عام رمزاً للفخر في المدينة.'),
  'cangzhou/martial': ('الفنون القتالية', 'تُلقب بموطن الووشو في الصين، حيث خرج منها أشهر الأساتذة ومدارس الفنون القتالية.'),
  'cangzhou/canal': ('القناة الكبرى', 'تخترق القناة الكبرى الرابطة بين بكين وهانغتشو المدينة، ولا تزال أرصفتها القديمة قائمة حتى اليوم.'),
  'cangzhou/jujube': ('العناب الذهبي', 'يُعرف عناب الخيط الذهبي ذو القشرة الرقيقة والمذاق الحلو بكونه ملك الفواكه المجففة.'),
  'nantong/textile': ('مدينة المنسوجات', 'تُعد نانتونغ عاصمة المنسوجات المنزلية في الصين، حيث تصل أقمشتها القطنية إلى الأسواق في جميع أنحاء العالم.'),
  'nantong/mountain': ('جبل لانغ', 'يرتفع هذا الجبل المقدس ذو القمم الخمس عند مصب نهر يانغتسي، ويُعد وجهة شهيرة للحج والاستمتاع بالمناظر الطبيعية.'),
  'nantong/kite': ('طائرات بانيو الورقية', 'تُعتبر طائرات "بانيو" الورقية المزودة بصفارات طنين حرفة تقليدية عريقة تشتهر بها المدينة.'),
  'nantong/school': ('رائد التعليم', 'أسس الصناعي تشانغ جيان هنا أول مدرسة ومتحف حديث في الصين.'),
  'taizhou/opera': ('مي لان فانغ', 'تُعد هذه المدينة مسقط رأس مي لان فانغ، الأستاذ الأسطوري لأوبرا بكين.'),
  'taizhou/tea': ('شاي الصباح', 'يُعتبر طقس "تساوتشا" الصباحي، الذي يجمع بين تناول الكعك المطهو على البخار وشرب الشاي، تقليداً أصيلاً في المدينة.'),
  'taizhou/boat': ('مهرجان قينتونغ للقوارب', 'في فصل الربيع، ينبض النهر بالحياة خلال مهرجان يضم مئات المجدفين في سباقات حماسية.'),
  'taizhou/meatball': ('كرات لحم رأس الأسد', 'تُعد كرات لحم الخنزير الطرية والكبيرة المعروفة باسم "رأس الأسد" طبقاً كلاسيكياً من مطبخ هوايانغ.'),
  'jinhua/ham': ('لحم جينهوا المقدد', 'يُعد هذا اللحم الأحمر، الذي يُعالج بطريقة تعود لقرون مضت، الأشهر من نوعه في الصين.'),
  'jinhua/film': ('استوديوهات هنغديان', 'تُعد أكبر موقع تصوير سينمائي خارجي في العالم، حيث يتم تصوير عدد لا يحصى من الأعمال الدرامية التاريخية.'),
  'jinhua/cave': ('كهف شوانغ لونغ', 'كهف تحت الأرض يخطف الأنفاس، حيث يتم الدخول إليه عبر قارب يمر من بوابة صخرية منخفضة.'),
  'jinhua/bridge': ('الجسور القديمة', 'تجسد الجسور الحجرية المقوسة والبلدات المائية سحر منطقة جيانغنان وجمالها.'),
  'wuhu/park': ('فانغتي وندرلاند', 'تُعد واحدة من أكبر مدن الملاهي في الصين، وتوفر للعائلات أياماً مليئة بالإثارة والمرح.'),
  'wuhu/ironart': ('الرسم بالحديد', 'تُعتبر "اللوحات الحديدية" الأنيقة التي تُصاغ من الحديد المطاوع حرفة يدوية يعود تاريخها إلى 300 عام.'),
  'wuhu/rice': ('ميناء الأرز', 'كانت هذه المدينة الواقعة على ضفاف نهر يانغتسي تاريخياً أكبر سوق للأرز في الصين.'),
  'wuhu/river': ('ميناء يانغتسي', 'يُعد هذا الميناء النهري النشط البوابة الرئيسية لمدينة ووهو نحو البحر في مقاطعة آنهوي.'),
  'huangshan/peak': ('الجبل الأصفر', 'يُعتبر الجبل الأشهر في الصين بفضل قمم الجرانيت وبحر السحب وأشجار الصنوبر الملتوية.'),
  'huangshan/village': ('قرية هونغ تسون', 'تُدرج هذه القرية ذات الجدران البيضاء والممرات المائية ضمن قائمة اليونسكو، وتبدو وكأنها لوحة فنية مرسومة.'),
  'huangshan/tea': ('شاي ماوفنغ', 'يُقطف هذا الشاي الأخضر ذو البراعم الزغبية من المنحدرات الضبابية، ويُصنف ضمن أنواع الشاي العشرة الأكثر شهرة في الصين.'),
  'huangshan/ink': ('حبر وفنون هويتشو', 'يُمثل حبر هوي والمنازل الخشبية المنحوتة وفن الخط الكنوز الثقافية لهذه المنطقة.'),
  'yichun/moon': ('جبل مينغيويه', 'يشتهر جبل "القمر الساطع" بينابيعه الحارة وإطلالاته البانورامية عبر التلفريك.'),
  'yichun/spring': ('الينابيع الحارة', 'جعلت الينابيع الحارة النادرة والغنية بالسيلينيوم من المدينة مركزاً للاستشفاء في الصين.'),
  'yichun/zen': ('بوذية تشان', 'تدعو المعابد الجبلية المتجذرة في طوائف "تشان" الصينية الزوار إلى السكينة والتأمل.'),
  'yichun/rice': ('سهل الأرز', 'لطالما كان سهل يوان-هي الخصيب بمثابة مخزن الحبوب لمقاطعة جيانغشي.'),
  'zhangzhou/narcissus': ('النرجس', 'تنمو هنا أشهر أبصال النرجس في الصين، والتي تُعد رمزاً لاحتفالات الربيع.'),
  'zhangzhou/tulou': ('بيوت التولو', 'تُعد هذه القلاع الدائرية الضخمة المبنية من التربة المدكوكة موقعاً تراثياً لليونسكو، وتجمع القرية بأكملها تحت سقف واحد.'),
  'zhangzhou/banana': ('الفواكه الاستوائية', 'تُحافظ بساتين الموز واللونغان واليوسفي على اخضرار الدلتا الدافئة طوال العام.'),
  'zhangzhou/coast': ('جزيرة دونغشان', 'تُعتبر الجزيرة لؤلؤة الساحل الجنوبي بفضل شواطئها الذهبية وقراها التي يعمل سكانها في صيد الأسماك.'),
  'guangzhou/tower': ('برج كانتون', 'يُعرف ببرج "الخصر النحيل"، وهو من بين أطول الأبراج في العالم، ويتوج المدينة بألوانه المتغيرة ليلاً.'),
  'guangzhou/dimsum': ('شاي الصباح', 'يُعد "يام تشا"، وهو عبارة عن وجبات ديم سام المطهوة بالبخار في سلال الخيزران مع الشاي، روح المائدة الكانتونية.'),
  'guangzhou/academy': ('أكاديمية عشيرة تشن', 'تُعد قاعة العشيرة هذه تحفة فنية من الحرف اليدوية الكانتونية، وتشتهر بمنحوتاتها الخشبية وزخارفها الخزفية البديعة.'),
  'guangzhou/flower': ('مدينة الزهور', 'تُلقب غوانزو بـ "مدينة الزهور" نظراً لتفتح أزهارها طوال العام وإقامة معارض ضخمة للزهور في كل رأس سنة جديدة.'),
  'wuhan/crane': ('برج الكركي الأصفر', 'يطل هذا البرج الذي يعود تاريخه إلى ألف عام على نهر يانغتسي، وقد ألهم بعضاً من أشهر القصائد في تاريخ الصين.'),
  'wuhan/noodle': ('نودلز ساخنة وجافة', 'تعتبر النودلز الساخنة والجافة الممزوجة بمعجون السمسم وجبة الإفطار التي لا غنى عنها في مدينة ووهان.'),
  'wuhan/duckneck': ('رقبة البط الحارة', 'تعد رقبة البط المطهوة بالتوابل الحارة الوجبة الخفيفة المفضلة لسكان المدينة أثناء جلسات السمر الليلية.'),
  'wuhan/university': ('أزهار الكرز الجامعية', 'تجذب أزهار الكرز في جامعة ووهان آلاف الزوار للاستمتاع بجمالها في كل فصل ربيع.'),
  'tianjin/eye': ('عين تيانجين', 'هي عجلة ترفيهية ضخمة بُنيت فوق جسر، وتوفر إطلالة بانورامية على ضفتي النهر في آن واحد.'),
  'tianjin/baozi': ('فطائر غوبولي', 'تُعد فطائر لحم الخنزير المطهوة على البخار والمزينة بطيات دقيقة العلامة المميزة للمدينة منذ أكثر من 150 عاماً.'),
  'tianjin/crosstalk': ('كوميديا شيانغشينغ', 'تُعد كوميديا "شيانغشينغ" الحوارية بين شخصين تقليداً متأصلاً في تيانجين نشأ في مقاهي الشاي الخاصة بها.'),
  'tianjin/architecture': ('الحي الأوروبي', 'أكسبت الفيلات ذات الطراز الأوروبي في منطقة "الجادات الخمس" المدينة لقب "متحف العمارة".'),
  'xiamen/island': ('جزيرة غولانغيو', 'بفضل ممراتها الخالية من السيارات وفيلاتها الاستعمارية، تُعد هذه الجزيرة المدرجة ضمن قائمة اليونسكو متحفاً في الهواء الطلق.'),
  'xiamen/piano': ('جزيرة البيانو', 'تُلقب غولانغيو بـ "جزيرة البيانو" نظراً لامتلاكها أكبر عدد من آلات البيانو للفرد الواحد مقارنة بأي مكان آخر.'),
  'xiamen/egret': ('البلشون الأبيض', 'يُعتبر طائر البلشون الأبيض رمزاً للمدينة، وهو ما يذكرنا باسمها القديم "جزيرة البلشون".'),
  'xiamen/oyster': ('عجة المحار', 'تُعد عجة المحار المقرمشة المكونة من المحار الطازج والبيض الطبق الأبرز في مطبخ المناطق الساحلية.'),
  'harbin/ice': ('مهرجان الجليد', 'يُعد مهرجان الشتاء في هاربين، الذي يضم قصوراً جليدية عملاقة مضاءة، الأكبر من نوعه في العالم.'),
  'harbin/cathedral': ('كاتدرائية القديسة صوفيا', 'تُعد هذه الكاتدرائية الأرثوذكسية الروسية ذات القباب البصلية رمزاً لماضي المدينة الأوروبي.'),
  'harbin/sausage': ('السجق الأحمر', 'يُعتبر السجق الأحمر المدخن على الطريقة الروسية من الأطباق الشهية التي تشتهر بها المدينة منذ قرن من الزمان.'),
  'harbin/accordion': ('مدينة الموسيقى', 'بفضل تراثها الروسي العريق، احتضنت مدينة هاربين أول أوركسترا سيمفونية في الصين.'),
  'fuzhou/alley': ('الأزقة الثلاثة والحارات السبع', 'يُعد هذا الحي القديم بجدرانه البيضاء وقرميده الأسود متحفاً حياً للعمارة التي تعود لعصر سلالتي مينغ وتشينغ.'),
  'fuzhou/banyan': ('مدينة أشجار البانيان', 'تُلقب فوتشو بمدينة البانيان، حيث تظلل أشجار البانيان العملاقة والقديمة شوارعها.'),
  'fuzhou/hotspring': ('الينابيع الحارة', 'تتدفق الينابيع الحارة في وسط المدينة وتغذي الحمامات العامة منذ ألف عام.'),
  'fuzhou/soup': ('حساء بوذا يقفز فوق الجدار', 'يُعد هذا الحساء الفاخر، المطهو من عشرات المكونات، تحفة المطبخ في مقاطعة فوجيان.'),
  'dongguan/robot': ('مصنع العالم', 'بفضل مصانعها المؤتمتة، تنتج دونغوان حصة ضخمة من الإلكترونيات في العالم.'),
  'dongguan/basketball': ('مدينة كرة السلة', 'يقع مقر أكثر أندية كرة السلة تتويجاً في الصين داخل هذه المدينة المعروفة بمدينة كرة السلة.'),
  'dongguan/keyuan': ('حديقة كيوان', 'تُعد واحدة من الحدائق الكلاسيكية الأربع الشهيرة في مقاطعة غوانغدونغ، وتشتهر ببركها وأجنحتها.'),
  'dongguan/cannon': ('حصون هومين', 'تُمثل حصون هومين، حيث بدأت حرب الأفيون، الموقع الساحلي الذي أُحرقت فيه شحنات الأفيون.'),
  'lanzhou/beefnoodle': ('نودلز لحم البقر في لانتشو', 'بمرقها الصافي ونودلزها المسحوبة يدوياً، تُعتبر لانتشو عاصمة النودلز في الصين.'),
  'lanzhou/waterwheel': ('النواعير المائية', 'ترمز النواعير المائية العملاقة على ضفاف النهر الأصفر إلى قرون من هندسة الري.'),
  'lanzhou/statue': ('تمثال الأم للنهر الأصفر', 'يجسد تمثال الأم وطفلها على ضفة النهر، النهر الذي غذى الحضارة الصينية.'),
  'lanzhou/raft': ('قوارب جلد الغنم', 'لا تزال القوارب التقليدية المصنوعة من جلود الغنم المنفوخة تطفو فوق مياه النهر الأصفر.'),
  'urumqi/bazaar': ('البازار الكبير', 'يتميز البازار بأبراج مآذنه وأكشاك التوابل التي تعكس ألوان طريق الحرير الزاهية.'),
  'urumqi/tianshan': ('بحيرة تيانشي', 'تحيط غابات التنوب ببحيرة تيانشي التي تقع عند سفح قمم جبال تيانشان الثلجية.'),
  'urumqi/kebab': ('كباب لحم الضأن', 'يُعد كباب لحم الضأن المتبل والمشوي على الفحم طبقاً أساسياً على المائدة الأويغورية.'),
  'urumqi/dance': ('الرقص الأويغوري', 'تضفي الرقصات الأويغورية الدوارة على أنغام الطبول وآلة الرواب البهجة على كل الاحتفالات.'),
  'haikou/coconut': ('مدينة جوز الهند', 'تمنح أشجار جوز الهند التي تصطف على جانبي الشوارع مدينة هايكو لقبها الشهير بمدينة جوز الهند.'),
  'haikou/arcade': ('مباني تشيلو', 'تشكل مباني تشيلو ذات الأعمدة في جنوب الصين ممرات مظللة للمشاة.'),
  'haikou/crater': ('الفوهات البركانية', 'تُشكل الفوهات البركانية الخامدة حديقة جيولوجية خضراء على أطراف المدينة.'),
  'haikou/turtle': ('البحر الاستوائي', 'تجعل المياه الدافئة الصافية والشعاب المرجانية من الساحل موطناً للسلاحف البحرية.'),
  'luoyang/grotto': ('كهوف لونغمن', 'تُعد كهوف لونغمن التي تضم عشرات الآلاف من تماثيل بوذا المنحوتة في المنحدرات كنزاً فنياً مدرجاً ضمن قائمة اليونسكو.'),
  'luoyang/peony': ('عاصمة الفاوانيا', 'تتحول لويانغ إلى عاصمة للفاوانيا مع تفتح آلاف الزهور في شهر أبريل من كل عام.'),
  'luoyang/whitehorse': ('معبد الحصان الأبيض', 'يُعتبر هذا المعبد الذي تأسس عام 68 ميلادي أول دير بوذي في الصين.'),
  'luoyang/capital': ('العاصمة القديمة', 'تُعد لويانغ مهد الحضارة الصينية، حيث كانت عاصمة لثلاث عشرة سلالة حاكمة.'),
  'shantou/gongfutea': ('شاي غونغفو', 'يُعد شاي غونغفو في منطقة تشاوشان فناً من فنون الضيافة، حيث يُحضر بعناية في أكواب صغيرة.'),
  'shantou/beefpot': ('قدر اللحم الساخن', 'يشتهر قدر اللحم الساخن على طريقة تشاوشان، حيث تُطهى شرائح اللحم الطازجة الرقيقة في ثوانٍ معدودة.'),
  'shantou/opera': ('أوبرا تشاوتشو', 'تشتهر أوبرا تشاوتشو التي يعود تاريخها إلى 600 عام بأغانيها الرقيقة وأزيائها المطرزة.'),
  'shantou/harbor': ('ميناء شانتو', 'يُعد هذا الميناء بوابة تاريخية للتجارة البحرية وموطناً للعديد من الصينيين المغتربين.'),
  'baoding/mansion': ('قصر الحاكم', 'يُعتبر هذا القصر أعلى مقر إداري إقليمي في عهد أسرة تشينغ، وهو قاعة حكم محفوظة بعناية.'),
  'baoding/donkeyburger': ('شطيرة لحم الحمير', 'تُعد هذه الشطيرة المكونة من لحم الحمير المتبل داخل خبز مقرمش أشهر مأكولات الشارع في المنطقة.'),
  'baoding/balls': ('كرات الصحة', 'تُعد ممارسة تدوير كرات معدنية في راحة اليد تقليداً قديماً يعود لقرون مضت لتعزيز صحة اليدين.'),
  'baoding/reeds': ('مستنقعات باييانغديان', 'تُعد أكبر منطقة رطبة في شمال الصين، وهي ملاذ للطيور وسط غابات القصب وزهور اللوتس.'),
  'jilin/rime': ('صقيع جيلين', 'يُعتبر الصقيع الأبيض الذي يغطي الأشجار على ضفاف نهر سونغهوا واحداً من عجائب الطبيعة الأربع في الصين.'),
  'jilin/snowboard': ('منتجع التزلج', 'بفضل ثلوجها الكثيفة وموسمها الطويل، تُعد المدينة واحدة من أفضل وجهات التزلج في شمال البلاد.'),
  'jilin/meteorite': ('متحف النيازك', 'يحتضن المتحف أكبر نيزك صخري في العالم، والذي سقط على الأرض في عام 1976.'),
  'jilin/skate': ('نهر سونغهوا المتجمد', 'يتحول نهر سونغهوا في فصل الشتاء إلى حلبة تزلج طبيعية يرتادها المتزلجون والمتنزهون.'),
  'ordos/khan': ('ضريح جنكيز خان', 'يُعد هذا الضريح المهيب الذي يخلد ذكرى بطل السهوب جنكيز خان قلب الثقافة المغولية.'),
  'ordos/cashmere': ('الكشمير', 'يضع الكشمير المنسوج من صوف ماعز أوردوس المدينة في صدارة صناعة المنسوجات العالمية.'),
  'ordos/sanddune': ('الرمال الغنائية', 'تُعد الكثبان الرملية العملاقة التي تصدر طنيناً عند الانزلاق عليها الوجهة المفضلة في صحراء كوبوتشي.'),
  'ordos/yurt': ('الخيمة المغولية', 'ترمز الخيام المصنوعة من اللباد الأبيض والمنصوبة فوق المراعي الممتدة إلى نمط الحياة البدوي.'),
  'jining/confucius': ('معبد كونفوشيوس', 'يقع المعبد وقصر وضريح الحكيم كونفوشيوس في مدينة تشوفو المجاورة، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو.'),
  'jining/barge': ('القناة الكبرى', 'باعتبارها ميناءً نشطاً على قناة بكين-هانغتشو، كانت جينينغ مركزاً حيوياً لثقافة القنوات المائية.'),
  'jining/sword': ('أبطال ليانغشان', 'تجمع مئة وثمانية من الأبطال الخارجين عن القانون في هذه التلال المستنقعية، كما ورد في رواية "حافة الماء" الكلاسيكية.'),
  'jining/fishnet': ('بحيرة ويشان', 'يلقي الصيادون شباكهم بالطرق التقليدية القديمة في أكبر بحيرة للوتس في شمال الصين.'),
  'langfang/culture': ('مركز ثقافة طريق الحرير', 'يجمع هذا المركز الثقافي الحديث والضخم في المدينة فنون طريق الحرير تحت سقف واحد.'),
  'langfang/furniture': ('مدينة الأثاث', 'تعد منطقة شيانغخه المجاورة واحدة من أكبر مراكز تصنيع وتجارة الأثاث في الصين.'),
  'langfang/tunnel': ('أنفاق الحرب القديمة', 'تتبع هذه الأنفاق العسكرية التي حُفرت تحت الأرض منذ ألف عام خطوط الدفاع الحدودية القديمة.'),
  'langfang/themepark': ('منتزه المدينة رقم 1', 'يستقبل هذا المنتزه الترفيهي الواسع العائلات، حيث يعيد تجسيد مدينة قديمة مسورة.'),
  'yancheng/salt': ('مدينة الملح', 'يعني اسم يانتشينغ "حصن الملح"، فقد كانت لقرون مركزاً رئيسياً لإنتاج الملح في الصين.'),
  'yancheng/crane': ('الكركي أحمر التاج', 'تعتبر هذه الأراضي الرطبة الساحلية أكبر منطقة شتاء في العالم لطيور الكركي حمراء التاج البرية.'),
  'yancheng/elk': ('أيل الأب ديفيد', 'بعد أن انقرض أيل الميلو في البرية، عاد للتكاثر والعيش من جديد في هذه الأراضي الرطبة.'),
  'yancheng/wetland': ('الأراضي الرطبة الساحلية', 'تعد المسطحات الطينية المدرجة ضمن قائمة اليونسكو محطة عالمية للطيور المهاجرة.'),
  'huzhou/brush': ('فرشاة هو للخط', 'تُصنع هنا فرشاة "هو"، التي تُعد واحدة من "الكنوز الأربعة" للخط الصيني التقليدي.'),
  'huzhou/bamboo': ('بحر خيزران أنجي', 'تساهم غابات الخيزران الخضراء الممتدة، التي كانت مصدراً لإلهام العديد من الأفلام، في تلطيف هواء المنطقة.'),
  'huzhou/silkworm': ('دودة القز', 'لطالما كان الشاطئ الجنوبي لبحيرة تاي مركزاً لإنتاج حرير التوت منذ ألف عام.'),
  'huzhou/whitetea': ('شاي أنجي الأبيض', 'يُعد شاي أنجي الأبيض، بأوراقه الشاحبة ومذاقه الحلو، من بين أندر أنواع الشاي في الصين.'),
  'quzhou/go': ('لعبة غو', 'تُبجل المدينة باعتبارها "أرض الغو"، وذلك بفضل الأسطورة الشهيرة المرتبطة بجبل لانكي.'),
  'quzhou/peaks': ('جبل جيانغلانغ', 'تشكل الأعمدة الصخرية الثلاثة الضخمة التي تعانق السماء مشهداً طبيعياً فريداً مدرجاً ضمن قائمة اليونسكو.'),
  'quzhou/ponkan': ('يوسفي تشوتشو', 'يُعد اليوسفي ذو القشرة الحلوة هدية الشتاء التي تجود بها التلال المعتدلة في المنطقة.'),
  'quzhou/cake': ('خبز السمسم المخبوز', 'يُعتبر خبز السمسم المقرمش المخبوز على جدران الفرن وجبة إفطار تقليدية شهيرة في المدينة.'),
  'huainan/tofu': ('مهد التوفو', 'ابتُكر التوفو على جبل باغونغ قبل ألفي عام، ومن هنا انتشر ليصبح جزءاً من المطبخ العالمي.'),
  'huainan/coalmine': ('مدينة الفحم', 'تُعد هواينان قاعدة طاقة رئيسية في شرق الصين بفضل غناها بطبقات الفحم الوفيرة.'),
  'huainan/oldtown': ('مدينة شو القديمة', 'يُعد سور المدينة المحفوظ بالكامل من عهد أسرة سونغ مثالاً نادراً على فن العمارة الدفاعية القديمة.'),
  'huainan/classic': ('كتاب هواينانزي', 'كُتب هذا المرجع الفلسفي الكلاسيكي، الذي جمعه الأمير ليو آن، على هذه الأراضي التاريخية.'),
  'jingdezhen/porcelain': ('عاصمة الخزف', 'تُلقب المدينة بعاصمة الخزف في العالم، حيث ظلت تنتج الخزف الإمبراطوري لأكثر من ألف عام.'),
  'jingdezhen/kiln': ('الأفران القديمة', 'تحافظ أفران التنين التي تعمل بالحطب على استمرارية فن حرق الخزف التقليدي حتى يومنا هذا.'),
  'jingdezhen/bluewhite': ('الخزف الأزرق والأبيض', 'يُعد الخزف الأبيض المزخرف بنقوش زرقاء من الكوبالت العلامة التجارية الشهيرة للمدينة عالمياً.'),
  'jingdezhen/painting': ('الرسم على الخزف', 'تُعد القطع الخزفية التي يرسمها كبار الفنانين بفرش دقيقة تحفاً فنية تحظى بتقدير كبير.'),
  'jian/jinggang': ('جبال جينغغانغ', 'تُعتبر هذه الجبال الضبابية، التي كانت أول قاعدة للثورة، القلب النابض للسياحة الحمراء في الصين.'),
  'jian/torch': ('شرارة الثورة', 'تُعد هذه الأرض التي شهدت ولادة مقولة "شرارة واحدة يمكن أن تشعل سهلاً بأكمله" نصباً تذكارياً تاريخياً.'),
  'jian/academy': ('أكاديمية بايلوتشو', 'خرّجت هذه الأكاديمية التي يعود تاريخها إلى ألف عام، والواقعة على جزيرة في نهر غان، عدداً لا يحصى من العلماء الإمبراطوريين.'),
  'jian/pine': ('صنوبر جينغغانغ', 'ترمز أشجار الصنوبر الحمراء التي تشق طريقها عبر الضباب إلى روح الجبل والصمود.'),
  'nanping/wuyi': ('جبال وويي', 'تُعد هذه الجبال المدرجة ضمن قائمة اليونسكو كنزاً طبيعياً وثقافياً بفضل منحدراتها الحمراء ووديانها الخضراء.'),
  'nanping/rocktea': ('شاي الصخور', 'يُعتبر شاي أولونغ المعروف باسم "الرداء الأحمر الكبير"، والذي ينمو بين الصخور، من أغلى أنواع الشاي في العالم.'),
  'nanping/bambooraft': ('طوافات المنعطفات التسعة', 'تنساب طوافات الخيزران التقليدية بهدوء عبر مجرى مياه المنعطفات التسعة بين المنحدرات الصخرية الحمراء.'),
  'nanping/scholar': ('المعلم تشو شي', 'درّس المعلم تشو شي، مؤسس الكونفوشيوسية الجديدة، عند سفح هذه الجبال.'),
  'beijing/great-wall': ('سور الصين العظيم', 'يُعد هذا السور أطول تحصين في العالم، حيث يمتد لأكثر من 20 ألف كيلومتر، وتُعتبر منطقة بادالينغ بالقرب من بكين أكثر أجزائه زيارةً بفضل درجاته الحجرية وأبراج مراقبته.'),
  'beijing/temple': ('معبد السماء', 'مجمع مقدس كان أباطرة أسرتي مينغ وتشينغ يصلون فيه سنوياً طلباً لحصاد وفير، ويشتهر بسقفه الأزرق المستدير المكون من ثلاث طبقات والذي بُني دون استخدام مسمار واحد.'),
  'beijing/pagoda': ('معبد تياننينغ', 'يُعد هذا المعبد، الذي يعود تاريخه إلى أسرة لياو، واحداً من أقدم الهياكل الباقية في بكين، ويتميز بتصميمه المثمن ونقوشه البارزة التي تشهد على تاريخ المدينة العريق.'),
  'beijing/opera': ('أوبرا بكين', 'فن مسرحي صيني تقليدي يجمع بين الغناء والحوار والفنون القتالية، حيث تكشف وجوه الممثلين الملونة عن طبيعة شخصياتهم، فاللون الأحمر يرمز للولاء والأبيض للمكر.'),
};
